import { useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import { 
  FiEye, FiEyeOff, FiTrendingUp, FiTrendingDown, 
  FiActivity, FiTarget, FiAlertCircle, FiPlusCircle, 
  FiArrowRight, FiFileText 
} from "react-icons/fi";
import style from "../style/LeftSite.module.css";
import {
  CURRENCY_OPTIONS,
  filterMovimientosByCurrency,
  formatMoney,
  getCurrencyMeta,
  isSameMonth,
  summarizeByType,
} from "../utils/finance";

function LeftSite({ movimientos = [], currentCurrency, onCurrencyChange }) {
  const navigate = useNavigate();
  const [areTotalsVisible, setAreTotalsVisible] = useState(true);

  const currencyMeta = getCurrencyMeta(currentCurrency);

  const currencyMovimientos = useMemo(
    () => filterMovimientosByCurrency(movimientos, currentCurrency),
    [movimientos, currentCurrency]
  );

  const monthMovimientos = useMemo(
    () => currencyMovimientos.filter((m) => isSameMonth(m.fecha)),
    [currencyMovimientos]
  );

  const historicalSummary = useMemo(() => summarizeByType(currencyMovimientos), [currencyMovimientos]);
  const monthSummary = useMemo(() => summarizeByType(monthMovimientos), [monthMovimientos]);

  const hideableMoney = (amount) =>
    areTotalsVisible ? formatMoney(amount, currentCurrency) : "••••••";

  return (
    <aside className={style.container}>
      <div className={style.panel}>

        {/* Encabezado Dinámico */}
        <header className={style.headerBlock}>
          <p className={style.eyebrow}>Finanzas Personales</p>
          <h2>Mi Caja <span className={style.currencyTag}>{currencyMeta.codeLabel}</span></h2>
        </header>

        {/* Tarjeta de Saldo Principal */}
        <div className={style.balanceCard}>
          <div className={style.balanceInfo}>
            <p className={style.balanceLabel}>Saldo Disponible</p>
            <h3 className={style.balanceValue}>{hideableMoney(historicalSummary.total)}</h3>
            <p className={style.balanceHint}>
              {currencyMovimientos.length} transacciones totales
            </p>
          </div>
          <button 
            onClick={() => setAreTotalsVisible(!areTotalsVisible)} 
            className={style.visibilityBtn}
            title={areTotalsVisible ? "Ocultar saldos" : "Mostrar saldos"}
          >
            {areTotalsVisible ? <FiEyeOff /> : <FiEye />}
          </button>
        </div>

        {/* Selector de Moneda tipo "Pill" */}
        <div className={style.currencyPicker}>
          {CURRENCY_OPTIONS.map((option) => (
            <button
              key={option.value}
              className={`${style.pickerOption} ${option.value === currentCurrency ? style.activePicker : ""}`}
              onClick={() => onCurrencyChange?.(option.value)}
            >
              {option.codeLabel}
            </button>
          ))}
        </div>

        {/* Grid de Estadísticas con Iconos */}
        <div className={style.statGrid}>
          <div className={`${style.statCard} ${style.ingreso}`}>
            <div className={style.statHeader}>
              <FiTrendingUp /> <span>Ingresos Mes</span>
            </div>
            <strong>{hideableMoney(monthSummary.ingreso)}</strong>
          </div>

          <div className={`${style.statCard} ${style.egreso}`}>
            <div className={style.statHeader}>
              <FiTrendingDown /> <span>Gastos Mes</span>
            </div>
            <strong>{hideableMoney(monthSummary.egreso)}</strong>
          </div>

          <div className={`${style.statCard} ${style.ahorro}`}>
            <div className={style.statHeader}>
              <FiTarget /> <span>Ahorro</span>
            </div>
            <strong>{hideableMoney(monthSummary.ahorro)}</strong>
          </div>

          <div className={`${style.statCard} ${style.deuda}`}>
            <div className={style.statHeader}>
              <FiAlertCircle /> <span>Deudas</span>
            </div>
            <strong>{hideableMoney(historicalSummary.deudaPendiente)}</strong>
          </div>
        </div>

        {/* Accesos Rápidos Estilizados */}
        <section className={style.quickActionsSection}>
          <div className={style.sectionHeader}>
            <h4>Accesos Rápidos</h4>
          </div>
          <div className={style.actionButtons}>
            <button onClick={() => navigate("/add")} className={style.mainAction}>
              <FiPlusCircle /> Nueva Carga
            </button>
            <div className={style.secondaryActions}>
              <button onClick={() => navigate("/")}><FiActivity /> Dashboard</button>
              <button onClick={() => navigate("/notas")}><FiFileText /> Notas</button>
            </div>
          </div>
        </section>
      </div>
    </aside>
  );
}

export default LeftSite;
